219	  it.todo("claim on dragon-material sword ench 8, damage 1000 → payout 400 (high-enchantment clause applies, then deductible)");
220	
221	  // --- Claim: payout rounding ---
222	  it.todo("payout calculation yielding 350.5 rounds down to 350 (in MHPCO's favor)");
223	
224	  // --- Multiple items of the same type ---
225	  it.todo("policy covering two swords has insurance sum 2000 and cap 4000");
226	  it.todo("dragon attack damaging both swords (two sword entries) treats each as separate damage with own deductible");
227	
228	  // --- Cap ---
229	  it.todo("policy covering sword + amulet has insurance sum 1600 and cap 3200");
230	  it.todo("cap is based on unmodified insurance value: cursed sword has cap 2000 regardless of premium modifiers");
231	  it.todo("policy covering sword + 3 runes has insurance sum 1750 (block discount affects premium only, not insurance sum)");
232	
